error_handling.fastapi_error_handler_pattern:
# backend/app/api/v1/routes.py
from fastapi import HTTPException
from langchain_core.messages import HumanMessage

@router.post("/chat", response_model=ChatResponse)
async def chat(request: ChatRequest, req: Request):
    try:
        result = await req.app.state.graph.ainvoke(
            {"messages": [HumanMessage(content=request.message)]},
            config={"configurable": {"thread_id": request.session_id}},
        )
        content = result["messages"][-1].content
        return ChatResponse(session_id=request.session_id, content=content)
    except Exception as e:
        logger.error("Graph invocation failed for session %s: %s", request.session_id, str(e))
        raise HTTPException(status_code=500, detail="Agent system error. Check server logs.")

logging.setup_pattern:
# backend/app/main.py import logging import sys
def setup_logging(log_level: str = "INFO") -> None: logging.basicConfig( level=getattr(logging, log_level.upper(), logging.INFO), format="%(asctime)s | %(levelname)s | %(name)s | %(message)s", handlers=[logging.StreamHandler(sys.stdout)], )
# Call in lifespan startup before anything else: setup_logging(settings.log_level)
